select s.id, s.name, s.no, s.gender, s.phone, s.address, s.degree, s.id_card, s.is_college, s.graduation_date, s.violation_count, s.violation_score, s.clazz_id, c.name clazzName, s.create_time, s.update_time from student s left join clazz c on s.clazz_id = c.id
